  sma50Line = [],
  high6mo,
  low6mo,
  latestClose,
  ticker,
}) {
  const containerRef = useRef(null);
  const chartRef     = useRef(null);

  useEffect(() => {
    if (!ohlcv || ohlcv.length === 0 || !containerRef.current) return;

    // ── Resolve CSS variables from :root ─────────────────────────────────
