".download-btn svg {
  flex-shrink: 0;
}

/* ── Stock / Candlestick chart ──────────────────────────────────── */
.stock-chart-wrap {
  margin-bottom: 16px;
  border-radius: 8px;
  overflow: hidden;
  border: 1px solid var(--border);
  background: var(--bg);
  animation: expandIn 0.3s ease;
}

.stock-chart-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 12px;
  border-bottom: 1px solid var(--border);
  background: var(--surface);
  gap: 12px;
  flex-wrap: wrap;
}

.stock-chart-title {
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--text-dim);
  font-family: ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, monospace;
}

.stock-chart-legend {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 11px;
  color: var(--text-dim);
  font-family: ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, monospace;
}

.legend-dot {
  display: inline-block;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
  margin-right: 3px;
}

.legend-dot--accent { background: var(--accent); }
.legend-dot--amber  { background: var(--amber); }
.legend-dot--green  { background: rgba(62, 207, 142, 0.55); }
.legend-dot--red    { background: rgba(239, 91, 91, 0.55); }
"

