".verdict-badge.invest { background: rgba(62,207,142,0.15); color: var(--green); }
.verdict-badge.pass { background: rgba(239,91,91,0.15); color: var(--red); }
.verdict-badge.watch { background: rgba(240,180,41,0.15); color: var(--amber); }

/* Verdict badge icon prefix */
.verdict-badge-icon {
  font-size: 14px;
  margin-right: 6px;
  opacity: 0.85;
}

/* Wrapper that contains badge + meaning text */
.verdict-badge-wrap {
  display: flex;
  flex-direction: column;
  gap: 10px;
  flex: 1;
  min-width: 0;
}

/* Plain-English meaning of the verdict for new users */
.verdict-meaning {
  font-size: 13px;
  line-height: 1.55;
  color: var(--text-dim);
  margin: 0;
  max-width: 480px;
}

/* Right-side column: gauge + band label + hint */
.verdict-gauge-col {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  flex-shrink: 0;
}

.confidence-band {
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 0.02em;
  text-align: center;
}

.confidence-hint {
  font-size: 10px;
  color: var(--text-dim);
  text-align: center;
  max-width: 140px;
  line-height: 1.4;
}

/* ── Confidence scale legend ───────────────────────────────────────── */
.confidence-scale {
  margin: 14px 0 4px;
  padding: 10px 14px;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 8px;
}

.cs-label {
  display: block;
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.07em;
  color: var(--text-dim);
  margin-bottom: 8px;
}

.cs-bars {
  display: flex;
  flex-wrap: wrap;
  gap: 6px 18px;
}

.cs-bar-item {
  display: flex;
  align-items: center;
  gap: 6px;
}

.cs-dot {
  width: 8px;
